-- helper: depth-first search for first node with given tag
local function find_node(node, tag)
    if type(node) == "table" and node.tag == tag then
        return node
    end
    if type(node) == "table" then
        for _, child in ipairs(node) do
            if type(child) == "table" then
                local f = find_node(child, tag)
                if f then return f end
            end
        end
    end
end

-- helper: convert XML LOM tree to Lua table
local function xml_to_table(node)
    if type(node) ~= "table" then
        return node
    end
    local t = {}
    if node.attr then
        for k, v in pairs(node.attr) do
            t["@" .. k] = v
        end
    end
    local textbuf
    for _, child in ipairs(node) do
        if type(child) == "table" then
            local entry = xml_to_table(child)
            local tag = child.tag
            if t[tag] then
                if type(t[tag][1]) ~= "table" then
                    t[tag] = { t[tag] }
                end
                table.insert(t[tag], entry)
            else
                t[tag] = entry
            end
        else
            textbuf = (textbuf or "") .. child
        end
    end
    if textbuf and textbuf:gsub("%s+", "") ~= "" then
        t["#text"] = textbuf
    end
    return t
end

-- locate SOAP envelope/body if present
local envelope = find_node(parsed, "Envelope") or find_node(parsed, "soap:Envelope") or parsed
local body_node = find_node(envelope, "Body") or find_node(envelope, "soap:Body")
